// PoolPlay Trivia Questions
// Place this file in the same directory as index.html on your server.
// getAllQ() returns today’s 10-question set, cycling every 29 days.

function getAllQ() {
var all = _ppBank();
try {
var now = new Date();
var jan = new Date(now.getFullYear(),0,1);
var jul = new Date(now.getFullYear(),6,1);
var isDST = now.getTimezoneOffset() < Math.max(jan.getTimezoneOffset(), jul.getTimezoneOffset());
var utc = now.getTime() + now.getTimezoneOffset()*60000;
var et = new Date(utc + (isDST ? -4 : -5)*3600000);
var launch = Date.UTC(2026,2,8);
var eMidnight = Date.UTC(et.getFullYear(),et.getMonth(),et.getDate());
var diff = Math.floor((eMidnight - launch)/(1000*60*60*24));
var idx = ((diff % all.length) + all.length) % all.length;
return all[idx];
} catch(e) { return all[0]; }
}

